## 🎯 改进任务提案

### **任务：实现 Dashboard SQLite 慢查询监控系统**

**优先级：** 🟡 P1（中等）  
**工作量：** 2-3 小时  
**影响：** 提升 Dashboard 性能可观测性

### 📋 任务详情

#### 问题陈述
当前 `src/dashboard/services/database.service.ts` 第 298-301 行的 `logSlowQueries()` 方法只有 TODO 标记：

```typescript
logSlowQueries(thresholdMs: number = 100): void {
  // TODO: 实现慢查询日志记录
  console.log(`📊 Slow query threshold: ${thresholdMs}ms`);
}
```

**影响：**
- 无法追踪性能瓶颈
- 查询优化缺少数据支持
- Dashboard 启动慢无法诊断

#### 解决方案

实现完整的慢查询监控、统计分析和可视化报告系统。

### 🔧 实施步骤（3步）

#### **Step 1: 创建数据库表（30分钟）**

创建 SQL 迁移脚本 `database/migrations/009_slow_query_monitoring.sql`：

```sql
-- 慢查询日志表
CREATE TABLE IF NOT EXISTS dashboard_slow_queries (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    sql_template TEXT NOT NULL,
    sql_full TEXT NOT NULL,
    execution_time_ms INTEGER NOT NULL,
    timestamp DATETIME DEFAULT CURRENT_TIMESTAMP,
    tags TEXT,
    stack_trace TEXT
);

-- 查询统计表
CREATE TABLE IF NOT EXISTS dashboard_query_stats (
    sql_template TEXT PRIMARY KEY,
    query_count INTEGER DEFAULT 0,
    total_time_ms INTEGER DEFAULT 0,
    avg_time_ms REAL DEFAULT 0,
    max_time_ms INTEGER DEFAULT 0,
    min_time_ms INTEGER DEFAULT 0,
    slow_count INTEGER DEFAULT 0,
    last_seen DATETIME DEFAULT CURRENT_TIMESTAMP
);

-- 索引
CREATE INDEX IF NOT EXISTS idx_slow_queries_time
  ON dashboard_slow_queries(execution_time_ms);

CREATE INDEX IF NOT EXISTS idx_slow_queries_timestamp
  ON dashboard_slow_queries(timestamp);
```

#### **Step 2: 实现监控逻辑（1.5小时）**

修改 `src/dashboard/services/database.service.ts` 的 `query()` 方法和 `logSlowQueries()` 方法：

```typescript
export class DatabaseService {
  private slowQueryThreshold: number = 100;

  query<T = any>(sql: string, params: any[] = []): T[] {
    const db = this.connect();
    const stmt = db.prepare(sql);
    const startTime = Date.now();

    try {
      const results = stmt.all(...params) as T[];
      const duration = Date.now() - startTime;

      // ✅ 核心功能：记录查询统计
      this.recordQuery(sql, params, duration);

      // ✅ 慢查询告警
      if (duration > this.slowQueryThreshold) {
        this.logSlowQuery(sql, params, duration);
        console.warn(`⚠️ Slow query (${duration}ms): ${sql.substring(0, 50)}...`);
      }

      return results;
    } catch (error) {
      console.error(`❌ Query failed: ${sql}`, error);
      throw error;
    }
  }

  private recordQuery(sql: string, params: any[], duration: number): void {
    const template = this.extractSqlTemplate(sql);

    this.execute(`
      INSERT OR REPLACE INTO dashboard_query_stats
      (sql_template, query_count, total_time_ms, avg_time_ms,
       max_time_ms, min_time_ms, slow_count, last_seen)
      VALUES (
        ?,
        COALESCE((SELECT query_count FROM dashboard_query_stats
                 WHERE sql_template = ?), 0) + 1,
        COALESCE((SELECT total_time_ms FROM dashboard_query_stats
                 WHERE sql_template = ?), 0) + ?,
        (COALESCE((SELECT total_time_ms FROM dashboard_query_stats
                 WHERE sql_template = ?), 0) + ?) /
        NULLIF((COALESCE((SELECT query_count FROM dashboard_query_stats
                        WHERE sql_template = ?), 0) + 1), 0),
        GREATEST(COALESCE((SELECT max_time_ms FROM dashboard_query_stats
                          WHERE sql_template = ?), 0), ?),
        CASE
          WHEN COALESCE((SELECT min_time_ms FROM dashboard_query_stats
                        WHERE sql_template = ?), 0) = 0 THEN ?
          ELSE LEAST(COALESCE((SELECT min_time_ms FROM dashboard_query_stats
                             WHERE sql_template = ?), 0), ?)
        END,
        CASE WHEN ? > 100 THEN 1 ELSE 0 END,
        CURRENT_TIMESTAMP
      )
    `, [template, template, template, duration,
        template, duration, template, duration,
        template, duration, template, duration, template, duration,
        duration > this.slowQueryThreshold ? 1 : 0]);
  }

  private logSlowQuery(sql: string, params: any[], duration: number): void {
    const template = this.extractSqlTemplate(sql);

    this.execute(`
      INSERT INTO dashboard_slow_queries
      (sql_template, sql_full, execution_time_ms, tags, stack_trace)
      VALUES (?, ?, ?, ?, ?)
    `, [
      template,
      this.formatSql(sql, params),
      duration,
      JSON.stringify({ params_count: params.length }),
      this.captureStackTrace()
    ]);
  }

  private extractSqlTemplate(sql: string): string {
    return sql.replace(/\?/g, '?').replace(/\$\d+/g, '$?')
              .replace(/:\w+/g, ':param').trim();
  }

  private formatSql(sql: string, params: any[]): string {
    let formatted = sql;
    params.forEach(p => {
      const value = typeof p === 'string' ? `'${p}'` : String(p);
      formatted = formatted.replace('?', value);
    });
    return formatted;
  }

  private captureStackTrace(): string {
    return new Error().stack?.split('\n').slice(3, 8).join('\n') || '';
  }

  /**
   * 慢查询日志（已实现）
   */
  logSlowQueries(thresholdMs: number = 100): void {
    this.slowQueryThreshold = thresholdMs;
    console.log(`📊 Slow query threshold set to: ${thresholdMs}ms`);
  }

  /**
   * 获取慢查询 TOP N
   */
  getSlowQueries(limit: number = 10): any[] {
    return this.query(`
      SELECT
        sql_template,
        COUNT(*) as occurrence,
        AVG(execution_time_ms) as avg_time,
        MAX(execution_time_ms) as max_time,
        MAX(timestamp) as last_seen
      FROM dashboard_slow_queries
      GROUP BY sql_template
      ORDER BY avg_time DESC
      LIMIT ?
    `, [limit]);
  }

  /**
   * 获取查询统计
   */
  getQueryStats(): any[] {
    return this.query(`
      SELECT * FROM dashboard_query_stats
      ORDER BY total_time_ms DESC
      LIMIT 100
    `);
  }
}
```

#### **Step 3: 添加 API 路由（1小时）**

创建 `src/dashboard/routes/performance.ts`：

```typescript
import { FastifyInstance } from 'fastify';
import { getDatabaseService } from '../services/database.service';

export async function performanceRoutes(fastify: FastifyInstance) {
  const db = getDatabaseService();

  // 慢查询 TOP N
  fastify.get('/api/performance/slow-queries', async (req, reply) => {
    const limit = parseInt((req.query as any).limit) || 10;
    const result = db.getSlowQueries(limit);
    return result;
  });

  // 查询统计
  fastify.get('/api/performance/query-stats', async (req, reply) => {
    const result = db.getQueryStats();
    return result;
  });

  // 性能趋势
  fastify.get('/api/performance/trend', async (req, reply) => {
    const days = parseInt((req.query as any).days) || 7;

    const result = db.query(`
      SELECT
        date(timestamp) as date,
        COUNT(*) as query_count,
        AVG(execution_time_ms) as avg_time,
        SUM(CASE WHEN execution_time_ms > 100 THEN 1 ELSE 0 END) as slow_count
      FROM dashboard_slow_queries
      WHERE timestamp > datetime('now', '-' || ? || ' days')
      GROUP BY date(timestamp)
      ORDER BY date DESC
    `, [days]);

    return result;
  });
}
```

在 `src/dashboard/server.ts` 注册路由：

```typescript
