/**
 * 数据库 Agent（增强版）
 */
import { BaseAgent } from '../base-agent';

const DATABASE_PROMPT = `
# 角色定义
你是资深数据库架构师，精通 PostgreSQL，擅长设计高效、可扩展的数据库架构。

# 核心能力
- 数据库设计
- SQL 优化
- 索引设计
- 数据迁移
- 性能分析与优化建议

# 输出
- ER 图
- 表结构
- 索引设计
- SQL 初始化脚本
- 性能优化建议报告
`;

export class DatabaseAgent extends BaseAgent {
  constructor() {
    super({
      role: '数据库',
      systemPrompt: DATABASE_PROMPT,
      allowedTools: ['Read', 'Write', 'Edit', 'Glob', 'Grep', 'Bash', 'WebSearch']
    });
  }

  getCapabilities(): string[] {
    return ['数据库设计', 'SQL编写', '索引优化', '数据迁移', '性能分析'];
  }

  /**
   * 🆕 分析数据库性能问题
   */
  analyzePerformance(sqlContent: string): string {
    const issues: string[] = [];
    const suggestions: string[] = [];

    // 检查 1: 缺少索引的查询
    if (sqlContent.includes('SELECT *') && !sqlContent.includes('CREATE INDEX')) {
      issues.push('发现 SELECT * 查询但未创建相应索引');
      suggestions.push('建议为常用查询字段创建索引');
    }

    // 检查 2: 潜在的 N+1 查询问题
    const selectCount = (sqlContent.match(/SELECT/gi) || []).length;
    if (selectCount > 5) {
      issues.push(`发现 ${selectCount} 个 SELECT 语句，可能存在 N+1 查询问题`);
      suggestions.push('建议使用 JOIN 或批量查询优化');
    }

    // 检查 3: 缺少约束
    if (!sqlContent.includes('FOREIGN KEY') && sqlContent.includes('REFERENCES')) {
      issues.push('外键关系未明确约束');
      suggestions.push('建议添加 FOREIGN KEY 约束保证数据完整性');
    }

    // 检查 4: 缺少时间戳字段
    if (!sqlContent.includes('created_at') && !sqlContent.includes('updated_at')) {
      issues.push('表缺少审计时间戳字段');
      suggestions.push('建议添加 created_at 和 updated_at 字段');
    }

    return this.generateOptimizationReport(issues, suggestions);
  }

  /**
   * 🆕 生成优化报告
   */
  private generateOptimizationReport(issues: string[], suggestions: string[]): string {
    if (issues.length === 0) {
      return '✅ 数据库设计良好，未发现明显性能问题。';
    }

    let report = '# 🔍 数据库性能优化建议\n\n';
    report += '## ⚠️ 发现的问题\n\n';

    issues.forEach((issue, index) => {
      report += `${index + 1}. ${issue}\n`;
    });

    report += '\n## 💡 优化建议\n\n';

    suggestions.forEach((suggestion, index) => {
      report += `${index + 1}. ${suggestion}\n`;
    });

    report += '\n## 📊 优先级\n\n';
    report += '- 🔴 高优先级: 索引优化\n';
    report += '- 🟡 中优先级: 查询重构\n';
    report += '- 🟢 低优先级: 约束完善\n';

    return report;
  }

  /**
   * 🆕 推荐索引设计
   */
  recommendIndexes(tableName: string, columns: string[]): string {
    let recommendations = `# 📑 索引设计建议 - ${tableName}\n\n`;

    // 主键索引
    recommendations += '## ✅ 已有索引\n';
    recommendations += `- PRIMARY KEY (id)\n\n`;

    // 推荐索引
    recommendations += '## 💡 推荐添加的索引\n\n';

    columns.forEach(column => {
      if (column.includes('_id') || column.includes('status')) {
        recommendations += ````sql\n`;
        recommendations += `CREATE INDEX idx_${tableName}_${column} ON ${tableName}(${column});\n`;
        recommendations += ````\n\n`;
      }
    });

    return recommendations;
  }
}
```

