#### 改进方案

实现 `DatabaseHealthChecker` 服务：

```typescript
/**
 * 数据库健康检查服务
 * 检测连接可用性、性能、完整性
 */
export class DatabaseHealthChecker {
  constructor(private db: DatabaseService) {}

  /**
   * 执行健康检查
   */
  async check(): Promise<HealthCheckResult> {
    const results: HealthCheckResult = {
      healthy: true,
      checks: {}
    };

    // 1. 连接可用性检查
    results.checks.connection = await this.checkConnection();

    // 2. 性能检查 (查询响应时间)
    results.checks.performance = await this.checkPerformance();

    // 3. 完整性检查
    results.checks.integrity = await this.checkIntegrity();

    // 4. WAL 模式检查
    results.checks.walMode = await this.checkWalMode();

    results.healthy = Object.values(results.checks).every(c => c.passed);
    return results;
  }

  /**
   * 检查连接可用性
   */
  private async checkConnection(): Promise<CheckResult> {
    try {
      const result = this.db.query('SELECT 1 as test');
      return {
        passed: result.length === 1 && result[0].test === 1,
        message: 'Connection OK',
        value: '1ms'
      };
    } catch (error) {
      return {
        passed: false,
        message: `Connection failed: ${error.message}`,
        value: null
      };
    }
  }

  /**
   * 检查查询性能
   */
  private async checkPerformance(): Promise<CheckResult> {
    const start = Date.now();
    try {
      this.db.query('SELECT COUNT(*) FROM iterations');
      const duration = Date.now() - start;

      return {
        passed: duration < 100, // 100ms 阈值
        message: `Query duration: ${duration}ms`,
        value: `${duration}ms`
      };
    } catch (error) {
      return {
        passed: false,
        message: error.message,
        value: null
      };
    }
  }

  /**
   * 检查数据库完整性
   */
  private async checkIntegrity(): Promise<CheckResult> {
    try {
      const result = this.db.query('PRAGMA integrity_check');
      return {
        passed: result.length === 1 && result[0].integrity_check === 'ok',
        message: 'Database integrity OK',
        value: 'ok'
      };
    } catch (error) {
      return {
        passed: false,
        message: `Integrity check failed: ${error.message}`,
        value: null
      };
    }
  }

  /**
   * 检查 WAL 模式
   */
  private async checkWalMode(): Promise<CheckResult> {
    try {
      const result = this.db.query('PRAGMA journal_mode');
      const mode = result[0]?.journal_mode?.toUpperCase();

      return {
        passed: mode === 'WAL',
        message: `Journal mode: ${mode}`,
        value: mode
      };
    } catch (error) {
      return {
        passed: false,
        message: error.message,
        value: null
      };
    }
  }
}
```

